 14	/// 话题列表 Notifier (支持分页、静默刷新和筛选)
 15	class TopicListNotifier extends AsyncNotifier<List<Topic>> {
 16	  TopicListNotifier(this._categoryId);
 17	
 18	  final int? _categoryId;
 19	
 20	  int _page = 0;
 21	  bool _hasMore = true;
 22	  bool _isLoadMoreFailed = false;
 23	  bool get hasMore => _hasMore;
 24	  bool get isLoadMoreFailed => _isLoadMoreFailed;
 25	
 26	  /// 分页助手
 27	  static final _paginationHelper = PaginationHelpers.forTopics<Topic>(
 28	    keyExtractor: (topic) => topic.id,
 29	  );
 30	
 31	  @override
 32	  Future<List<Topic>> build() async {
 33	    // 所有参数使用 ref.read（不建立依赖），
 34	    // 由 UI 层在参数变化时主动 invalidate provider
 35	    final currentFilter = ref.read(topicFilterProvider);
 36	    final tags = ref.read(tabTagsProvider(_categoryId));
 37	    final filter = _buildFilterParams(tags);
 38	    final sortOrder = ref.read(topicSortOrderProvider);
 39	    final sortAscending = ref.read(topicSortAscendingProvider);
 40	
 41	    _page = 0;
 42	    _hasMore = true;
 43	    _isLoadMoreFailed = false;
 44	
 45	    // 获取排序 API 参数
 46	    final orderParam = sortOrder.apiValue;
 47	    final ascendingParam = orderParam != null ? sortAscending : null;
 48	
 49	    // 优化：如果是 latest 列表且没有筛选条件且没有自定义排序，优先同步使用预加载数据
 50	    // 这样可以避免显示 loading 状态
 51	    if (currentFilter == TopicListFilter.latest && filter.isEmpty && orderParam == null) {
 52	      final preloadedService = PreloadedDataService();
 53	      final preloadedData = preloadedService.getInitialTopicListSync();
 54	      if (preloadedData != null) {
 55	        final result = _paginationHelper.processRefresh(
 56	          PaginationResult(items: preloadedData.topics, moreUrl: preloadedData.moreTopicsUrl),
 57	        );
 58	        _hasMore = result.hasMore;
 59	        return result.items;
 60	      }
 61	      if (preloadedService.hasInitialTopicList) {
 62	        final asyncPreloaded = await preloadedService.getInitialTopicList();
 63	        if (asyncPreloaded != null) {
 64	          final result = _paginationHelper.processRefresh(
 65	            PaginationResult(items: asyncPreloaded.topics, moreUrl: asyncPreloaded.moreTopicsUrl),
 66	          );
 67	          _hasMore = result.hasMore;
 68	          return result.items;
 69	        }
 70	      }
 71	    }
 72	
 73	    // 如果没有预加载数据，走正常的异步流程
 74	    final service = ref.read(discourseServiceProvider);
 75	    final response = await _fetchTopics(service, currentFilter, 0, filter, order: orderParam, ascending: ascendingParam);
 76	
 77	    final result = _paginationHelper.processRefresh(
 78	      PaginationResult(items: response.topics, moreUrl: response.moreTopicsUrl),
 79	    );
 80	    _hasMore = result.hasMore;
 81	    return result.items;
 82	  }
 83	
 84	  Future<TopicListResponse> _fetchTopics(
 85	    DiscourseService service,
 86	    TopicListFilter filter,
 87	    int page,
 88	    TopicFilterParams filterParams, {
 89	    String? order,
 90	    bool? ascending,
 91	  }) {
 92	    // 如果有筛选条件，使用 getFilteredTopics
 93	    if (filterParams.isNotEmpty) {
 94	      final filterName = _getFilterName(filter);
 95	      return service.getFilteredTopics(
 96	        filter: filterName,
 97	        categoryId: filterParams.categoryId,
 98	        categorySlug: filterParams.categorySlug,
 99	        parentCategorySlug: filterParams.parentCategorySlug,
100	        tags: filterParams.tags.isNotEmpty ? filterParams.tags : null,
101	        period: filter.period,
102	        page: page,
103	        order: order,
104	        ascending: ascending,
105	      );
106	    }
107	
108	    // 无筛选条件，使用原有方法
109	    switch (filter) {
110	      case TopicListFilter.latest:
111	        return service.getLatestTopics(page: page, order: order, ascending: ascending);
112	      case TopicListFilter.newTopics:
113	        return service.getNewTopics(page: page, order: order, ascending: ascending);
114	      case TopicListFilter.unread:
115	        return service.getUnreadTopics(page: page, order: order, ascending: ascending);
116	      case TopicListFilter.unseen:
117	        return service.getUnseenTopics(page: page, order: order, ascending: ascending);
118	      case TopicListFilter.top:
119	        return service.getTopTopics();
120	      case TopicListFilter.hot:
121	        return service.getHotTopics(page: page, order: order, ascending: ascending);
122	    }
123	  }
124	
125	  String _getFilterName(TopicListFilter filter) => filter.filterName;
126	
127	  /// 根据分类 ID 和标签构建筛选参数
128	  TopicFilterParams _buildFilterParams(List<String> tags) {
129	    if (_categoryId == null && tags.isEmpty) {
130	      return const TopicFilterParams();
131	    }
132	    if (_categoryId != null) {
133	      final categoryMap = ref.read(categoryMapProvider).value ?? {};
134	      final category = categoryMap[_categoryId];
135	      String? parentSlug;
136	      if (category?.parentCategoryId != null) {
137	        parentSlug = categoryMap[category!.parentCategoryId]?.slug;
138	      }
139	      return TopicFilterParams(
140	        categoryId: _categoryId,
141	        categorySlug: category?.slug,
142	        categoryName: category?.name,
143	        parentCategorySlug: parentSlug,
144	        tags: tags,
145	      );
146	    }
147	    return TopicFilterParams(tags: tags);
148	  }
149	
150	  /// 获取当前筛选参数（供非 build 方法使用）
151	  TopicFilterParams _currentFilterParams() {
152	    return _buildFilterParams(ref.read(tabTagsProvider(_categoryId)));
153	  }
154	
155	  /// 获取当前筛选模式
156	  TopicListFilter get _currentFilter => ref.read(topicFilterProvider);
157	
158	  /// 获取当前排序参数
159	  (String?, bool?) _currentSortParams() {
160	    final sortOrder = ref.read(topicSortOrderProvider);
161	    final orderParam = sortOrder.apiValue;
162	    final ascendingParam = orderParam != null ? ref.read(topicSortAscendingProvider) : null;
163	    return (orderParam, ascendingParam);
164	  }
