166	  /// 刷新列表
167	  Future<void> refresh() async {
168	    state = const AsyncValue.loading();
169	    state = await AsyncValue.guard(() async {
170	      _page = 0;
171	      _hasMore = true;
172	      _isLoadMoreFailed = false;
173	      final service = ref.read(discourseServiceProvider);
174	      final filterParams = _currentFilterParams();
175	      final (order, ascending) = _currentSortParams();
176	      final response = await _fetchTopics(service, _currentFilter, 0, filterParams, order: order, ascending: ascending);
177	
178	      final result = _paginationHelper.processRefresh(
179	        PaginationResult(items: response.topics, moreUrl: response.moreTopicsUrl),
180	      );
181	      _hasMore = result.hasMore;
182	      return result.items;
183	    });
184	  }
