186	  /// 静默刷新
187	  Future<void> silentRefresh() async {
188	    final service = ref.read(discourseServiceProvider);
189	    final filterParams = _currentFilterParams();
190	    final (order, ascending) = _currentSortParams();
191	    try {
192	      final response = await _fetchTopics(service, _currentFilter, 0, filterParams, order: order, ascending: ascending);
193	      _page = 0;
194	      _isLoadMoreFailed = false;
195	
196	      final result = _paginationHelper.processRefresh(
197	        PaginationResult(items: response.topics, moreUrl: response.moreTopicsUrl),
198	      );
199	      _hasMore = result.hasMore;
200	      state = AsyncValue.data(result.items);
201	    } catch (e) {
202	      debugPrint('Silent refresh failed: $e');
203	    }
204	  }
