206	  /// 按 topic_ids 加载并插入到列表顶部（对齐网页版 loadBefore）
207	  ///
208	  /// 1. 请求 /latest.json?topic_ids=xxx 获取这些话题的最新数据
209	  /// 2. 从当前列表中移除同 ID 旧数据（处理"更新的话题"）
210	  /// 3. 将 API 返回的话题全部插入列表顶部
211	  ///
212	  /// 返回实际被插入到顶部的 topic IDs（用于 UI 高亮）
213	  Future<List<int>> loadBefore(List<int> topicIds) async {
214	    if (topicIds.isEmpty) return [];
215	    final currentTopics = state.value;
216	    if (currentTopics == null) return [];
217	
218	    try {
219	      final service = ref.read(discourseServiceProvider);
220	      final response = await service.getTopicsByIds(topicIds);
221	      final newTopics = response.topics;
222	      if (newTopics.isEmpty) return [];
223	
224	      // 移除列表中已存在的同 ID 话题（刷新重复项，与网页版 removeValuesFromArray 一致）
225	      final newTopicIds = newTopics.map((t) => t.id).toSet();
226	      final remaining = currentTopics.where((t) => !newTopicIds.contains(t.id)).toList();
227	      // 将新话题全部插入列表顶部
228	      state = AsyncValue.data([...newTopics, ...remaining]);
229	      return newTopics.map((t) => t.id).toList();
230	    } catch (e) {
231	      debugPrint('[TopicList] loadBefore 失败: $e');
232	      return [];
233	    }
234	  }
