236	  /// 加载更多
237	  Future<void> loadMore() async {
238	    if (_isLoadMoreFailed) return; // 失败后需手动重试
239	    if (!_hasMore || state.isLoading) return;
240	
241	    // ignore: invalid_use_of_internal_member
242	    state = const AsyncLoading<List<Topic>>().copyWithPrevious(state);
243	
244	    final result = await AsyncValue.guard(() async {
245	      final currentTopics = state.requireValue;
246	      final nextPage = _page + 1;
247	
248	      final service = ref.read(discourseServiceProvider);
249	      final filterParams = _currentFilterParams();
250	      final (order, ascending) = _currentSortParams();
251	      final response = await _fetchTopics(service, _currentFilter, nextPage, filterParams, order: order, ascending: ascending);
252	
253	      final currentState = PaginationState(items: currentTopics);
254	      final paginationResult = _paginationHelper.processLoadMore(
255	        currentState,
256	        PaginationResult(items: response.topics, moreUrl: response.moreTopicsUrl),
257	      );
258	
259	      _hasMore = paginationResult.hasMore;
260	      if (paginationResult.items.length > currentTopics.length) {
261	        _page = nextPage;
262	      }
263	      return paginationResult.items;
264	    });
265	    if (result.hasError) {
266	      _isLoadMoreFailed = true;
267	      state = AsyncValue.data(state.requireValue);
268	    } else {
269	      state = result;
270	    }
271	  }
272	
273	  /// 手动重试加载更多
274	  void retryLoadMore() {
275	    _isLoadMoreFailed = false;
276	    loadMore();
277	  }
