279	  /// 刷新单条话题状态（用于 MessageBus 更新）
280	  Future<void> refreshTopic(int topicId) async {
281	    final currentTopics = state.value;
282	    if (currentTopics == null) return;
283	
284	    final existingIndex = currentTopics.indexWhere((t) => t.id == topicId);
285	    if (existingIndex == -1) {
286	      return;
287	    }
288	    final existingTopic = currentTopics[existingIndex];
289	
290	    try {
291	      final service = ref.read(discourseServiceProvider);
292	      final detail = await service.getTopicDetail(topicId);
293	
294	      final updatedTopic = Topic(
295	        id: detail.id,
296	        title: detail.title,
297	        slug: detail.slug,
298	        categoryId: detail.categoryId.toString(),
299	        postsCount: detail.postsCount,
300	        replyCount: detail.postsCount > 0 ? detail.postsCount - 1 : 0,
301	        views: existingTopic.views,
302	        likeCount: existingTopic.likeCount,
303	        lastPostedAt: existingTopic.lastPostedAt,
304	        pinned: existingTopic.pinned,
305	        tags: detail.tags ?? existingTopic.tags,
306	        posters: existingTopic.posters,
307	        unseen: false,
308	        unread: 0,
309	        lastReadPostNumber: detail.postsCount,
310	        highestPostNumber: detail.postsCount,
311	        lastPosterUsername: detail.postStream.posts.isNotEmpty
312	            ? detail.postStream.posts.last.username
313	            : existingTopic.lastPosterUsername,
314	      );
315	
316	      final newList = currentTopics.map((t) {
317	        return t.id == topicId ? updatedTopic : t;
318	      }).toList();
319	
320	      state = AsyncValue.data(newList);
321	    } catch (e) {
322	      debugPrint('[TopicList] 刷新话题 $topicId 失败: $e');
323	    }
324	  }
