326	  /// 忽略全部（新话题或未读话题）
327	  Future<void> dismissAll() async {
328	    final service = ref.read(discourseServiceProvider);
329	    final filter = _currentFilter;
330	    if (filter == TopicListFilter.newTopics) {
331	      await service.dismissNewTopics(categoryId: _categoryId);
332	      // 同步更新追踪状态计数
333	      ref.read(topicTrackingStateProvider.notifier)
334	          .dismissNewTopics(categoryId: _categoryId);
335	    } else if (filter == TopicListFilter.unread) {
336	      await service.dismissUnreadTopics(categoryId: _categoryId);
337	      // 同步更新追踪状态计数
338	      ref.read(topicTrackingStateProvider.notifier)
339	          .dismissUnreadTopics(categoryId: _categoryId);
340	    }
341	    state = const AsyncValue.data([]);
342	    _hasMore = false;
343	  }
