345	  void updateSeen(int topicId, int highestSeen) {
346	    final topics = state.value;
347	    if (topics == null) return;
348	
349	    final index = topics.indexWhere((t) => t.id == topicId);
350	    if (index == -1) return;
351	
352	    final topic = topics[index];
353	    final currentRead = topic.lastReadPostNumber ?? 0;
354	
355	    if (highestSeen <= currentRead) return;
356	
357	    final newUnread = (topic.highestPostNumber - highestSeen).clamp(0, topic.highestPostNumber);
358	
359	    final updated = Topic(
360	      id: topic.id,
361	      title: topic.title,
362	      slug: topic.slug,
363	      postsCount: topic.postsCount,
364	      replyCount: topic.replyCount,
365	      views: topic.views,
366	      likeCount: topic.likeCount,
367	      excerpt: topic.excerpt,
368	      createdAt: topic.createdAt,
369	      lastPostedAt: topic.lastPostedAt,
370	      lastPosterUsername: topic.lastPosterUsername,
371	      categoryId: topic.categoryId,
372	      pinned: topic.pinned,
373	      visible: topic.visible,
374	      closed: topic.closed,
375	      archived: topic.archived,
376	      tags: topic.tags,
377	      posters: topic.posters,
378	      unseen: false,
379	      unread: newUnread,
380	      newPosts: 0,
381	      lastReadPostNumber: highestSeen,
382	      highestPostNumber: topic.highestPostNumber,
383	    );
384	
385	    final newList = [...topics];
386	    newList[index] = updated;
387	    state = AsyncValue.data(newList);
388	
389	    // 同步更新追踪状态计数（阅读后减少 new/unread 计数）
390	    ref.read(topicTrackingStateProvider.notifier)
391	        .updateTopicRead(topicId, highestSeen, topic.highestPostNumber);
392	  }
393	}
