   8	/// 标签模型
   9	class Tag {
  10	  final int? id;
  11	  final String name;
  12	  final String? slug;
  13	
  14	  const Tag({
  15	    this.id,
  16	    required this.name,
  17	    this.slug,
  18	  });
  19	
  20	  factory Tag.fromJson(dynamic json) {
  21	    // 兼容新旧格式
  22	    if (json is String) {
  23	      // 旧格式：直接是字符串
  24	      return Tag(name: json);
  25	    } else if (json is Map<String, dynamic>) {
  26	      // 新格式：对象格式
  27	      return Tag(
  28	        id: json['id'] as int?,
  29	        name: json['name'] as String? ?? '',
  30	        slug: json['slug'] as String?,
  31	      );
  32	    } else {
  33	      // 降级处理
  34	      return Tag(name: json.toString());
  35	    }
  36	  }
  37	
  38	  @override
  39	  String toString() => name;
  40	
  41	  @override
  42	  bool operator ==(Object other) {
  43	    if (identical(this, other)) return true;
  44	    return other is Tag && other.name == name;
  45	  }
  46	
  47	  @override
  48	  int get hashCode => name.hashCode;
  49	}
