  51	/// 话题订阅级别
  52	enum TopicNotificationLevel {
  53	  muted(0),
  54	  regular(1),
  55	  tracking(2),
  56	  watching(3);
  57	
  58	  const TopicNotificationLevel(this.value);
  59	  final int value;
  60	
  61	  String get label {
  62	    switch (this) {
  63	      case TopicNotificationLevel.muted: return S.current.topic_levelMuted;
  64	      case TopicNotificationLevel.regular: return S.current.topic_levelRegular;
  65	      case TopicNotificationLevel.tracking: return S.current.topic_levelTracking;
  66	      case TopicNotificationLevel.watching: return S.current.topic_levelWatching;
  67	    }
  68	  }
  69	
  70	  String get description {
  71	    switch (this) {
  72	      case TopicNotificationLevel.muted: return S.current.topic_levelMutedDesc;
  73	      case TopicNotificationLevel.regular: return S.current.topic_levelRegularDesc;
  74	      case TopicNotificationLevel.tracking: return S.current.topic_levelTrackingDesc;
  75	      case TopicNotificationLevel.watching: return S.current.topic_levelWatchingDesc;
  76	    }
  77	  }
  78	
  79	  static TopicNotificationLevel fromValue(int? value) {
  80	    return TopicNotificationLevel.values.firstWhere(
  81	      (e) => e.value == value,
  82	      orElse: () => TopicNotificationLevel.regular,
  83	    );
  84	  }
  85	}
