1010	      if (raw == null) return const {};
1011	      final result = <int, List<int>>{};
1012	      for (final entry in raw.entries) {
1013	        final postId = int.tryParse(entry.key);
1014	        if (postId != null && entry.value is List) {
1015	          result[postId] = (entry.value as List).cast<int>();
1016	        }
1017	      }
1018	      return result;
1019	    }
1020	    return PostStreamGaps(
1021	      before: parseGapMap(json['before'] as Map<String, dynamic>?),
1022	      after: parseGapMap(json['after'] as Map<String, dynamic>?),
1023	    );
1024	  }
