1050	  /// 从顶层 JSON 解析 users/badges 数据，注入到 posts 中
1051	  /// [topLevelJson] 是包含 users、badges 字段的顶层响应 JSON
1052	  static void injectBadges(List<Post> posts, Map<String, dynamic> topLevelJson, List<dynamic>? rawPosts) {
1053	    // badge 数据在 topLevelJson['user_badges'] 下，包含 users 和 badges 两个子字典
1054	    final userBadgesContainer = topLevelJson['user_badges'] as Map<String, dynamic>?;
1055	    if (userBadgesContainer == null) return;
1056	
1057	    final badgesMap = <int, GrantedBadge>{};
1058	    final userBadgeIdsMap = <int, List<int>>{};
1059	
1060	    // 解析 badges（支持 Map 和 List 两种格式）
1061	    final badgesRaw = userBadgesContainer['badges'];
1062	    if (badgesRaw is Map<String, dynamic>) {
1063	      for (final entry in badgesRaw.entries) {
1064	        final badgeId = int.tryParse(entry.key);
1065	        if (badgeId != null && entry.value is Map<String, dynamic>) {
1066	          badgesMap[badgeId] = GrantedBadge.fromJson(entry.value as Map<String, dynamic>);
1067	        }
1068	      }
1069	    } else if (badgesRaw is List) {
1070	      for (final item in badgesRaw) {
1071	        if (item is Map<String, dynamic>) {
1072	          final badgeId = item['id'] as int?;
1073	          if (badgeId != null) {
1074	            badgesMap[badgeId] = GrantedBadge.fromJson(item);
1075	          }
1076	        }
1077	      }
1078	    }
1079	
1080	    // 解析 users（支持 Map 和 List 两种格式）
1081	    final usersRaw = userBadgesContainer['users'];
1082	    if (usersRaw is Map<String, dynamic>) {
1083	      for (final entry in usersRaw.entries) {
1084	        final userId = int.tryParse(entry.key);
1085	        if (userId != null && entry.value is Map<String, dynamic>) {
1086	          final badgeIds = (entry.value['badge_ids'] as List<dynamic>?)
1087	              ?.map((e) => e as int)
1088	              .toList();
1089	          if (badgeIds != null && badgeIds.isNotEmpty) {
1090	            userBadgeIdsMap[userId] = badgeIds;
1091	          }
1092	        }
1093	      }
1094	    } else if (usersRaw is List) {
1095	      for (final item in usersRaw) {
1096	        if (item is Map<String, dynamic>) {
1097	          final userId = item['id'] as int?;
1098	          final badgeIds = (item['badge_ids'] as List<dynamic>?)
1099	              ?.map((e) => e as int)
1100	              .toList();
1101	          if (userId != null && badgeIds != null && badgeIds.isNotEmpty) {
1102	            userBadgeIdsMap[userId] = badgeIds;
1103	          }
1104	        }
1105	      }
1106	    }
1107	
1108	    if (badgesMap.isEmpty || userBadgeIdsMap.isEmpty) return;
1109	
1110	    // 从原始 post JSON 中获取 user_id 映射
1111	    final postUserIdMap = <int, int>{};
1112	    if (rawPosts != null) {
1113	      for (final rawPost in rawPosts) {
1114	        if (rawPost is Map<String, dynamic>) {
1115	          final postId = rawPost['id'] as int?;
1116	          final userId = rawPost['user_id'] as int?;
1117	          if (postId != null && userId != null) {
1118	            postUserIdMap[postId] = userId;
1119	          }
1120	        }
1121	      }
1122	    }
1123	
1124	    for (int i = 0; i < posts.length; i++) {
1125	      final post = posts[i];
1126	      final userId = postUserIdMap[post.id];
1127	      if (userId != null) {
1128	        final badgeIds = userBadgeIdsMap[userId];
1129	        if (badgeIds != null) {
1130	          final badges = badgeIds
1131	              .map((id) => badgesMap[id])
1132	              .whereType<GrantedBadge>()
1133	              .toList();
1134	          if (badges.isNotEmpty) {
1135	            posts[i] = post.copyWith(badgesGranted: badges);
1136	          }
1137	        }
1138	      }
1139	    }
