1230	  factory TopicDetail.fromJson(Map<String, dynamic> json) {
1231	    var postStream = PostStream.fromJson(json['post_stream'] as Map<String, dynamic>);
1232	
1233	    // 注入 topic 级别的 badges 数据到每个 post
1234	    final rawPosts = (json['post_stream'] as Map<String, dynamic>)['posts'] as List<dynamic>?;
1235	    PostStream.injectBadges(postStream.posts, json, rawPosts);
1236	
1237	    // 解析 accepted_answer：topic 级别返回的是一个对象 {post_number, username, ...}
1238	    final acceptedAnswerData = json['accepted_answer'];
1239	    int? acceptedAnswerPostNumber;
1240	    bool hasAcceptedAnswer = false;
1241	
1242	    if (acceptedAnswerData is Map<String, dynamic>) {
1243	      // topic 级别的 accepted_answer 是一个对象
1244	      acceptedAnswerPostNumber = acceptedAnswerData['post_number'] as int?;
1245	      hasAcceptedAnswer = true;
1246	    }
1247	
1248	    // 备用方案：如果 topic 级别没有，从帖子的 topic_accepted_answer 或 accepted_answer 字段推断
1249	    if (!hasAcceptedAnswer) {
1250	      hasAcceptedAnswer = json['has_accepted_answer'] as bool? ?? false;
1251	    }
1252	    if (hasAcceptedAnswer && acceptedAnswerPostNumber == null) {
1253	      final acceptedPost = postStream.posts.where((p) => p.acceptedAnswer).firstOrNull;
1254	      acceptedAnswerPostNumber = acceptedPost?.postNumber;
1255	    }
1256	
1257	    // 解析书签数组：分别提取话题书签和帖子书签
1258	    bool topicBookmarked = false;
1259	    int? topicBookmarkId;
1260	    String? topicBookmarkName;
1261	    DateTime? topicBookmarkReminderAt;
1262	    // 帖子书签映射：bookmarkable_id -> bookmark data
1263	    final postBookmarks = <int, Map<String, dynamic>>{};
1264	    final bookmarksList = json['bookmarks'] as List<dynamic>?;
1265	    if (bookmarksList != null) {
1266	      for (final b in bookmarksList) {
1267	        if (b is Map<String, dynamic>) {
1268	          if (b['bookmarkable_type'] == 'Topic') {
1269	            topicBookmarked = true;
1270	            topicBookmarkId = b['id'] as int?;
1271	            final name = b['name'] as String?;
1272	            topicBookmarkName = (name != null && name.isNotEmpty) ? name : null;
1273	            topicBookmarkReminderAt = TimeUtils.parseUtcTime(b['reminder_at'] as String?);
1274	          } else if (b['bookmarkable_type'] == 'Post') {
1275	            final bookmarkableId = b['bookmarkable_id'] as int?;
1276	            if (bookmarkableId != null) {
1277	              postBookmarks[bookmarkableId] = b;
1278	            }
1279	          }
1280	        }
1281	      }
1282	    }
1283	
1284	    // 注入帖子书签数据到对应的 Post
1285	    if (postBookmarks.isNotEmpty) {
1286	      final updatedPosts = postStream.posts.map((post) {
1287	        final bm = postBookmarks[post.id];
1288	        if (bm != null) {
1289	          final bmName = bm['name'] as String?;
1290	          return post.copyWith(
1291	            bookmarked: true,
1292	            bookmarkId: bm['id'] as int?,
1293	            bookmarkName: (bmName != null && bmName.isNotEmpty) ? bmName : null,
1294	            bookmarkReminderAt: TimeUtils.parseUtcTime(bm['reminder_at'] as String?),
1295	          );
1296	        }
1297	        return post;
1298	      }).toList();
1299	      postStream = PostStream(posts: updatedPosts, stream: postStream.stream, gaps: postStream.gaps);
1300	    }
1301	
1302	    return TopicDetail(
1303	      id: json['id'] as int,
1304	      title: json['title'] as String? ?? '',
1305	      slug: json['slug'] as String? ?? '',
1306	      postsCount: json['posts_count'] as int? ?? 0,
1307	      postStream: postStream,
1308	      categoryId: json['category_id'] as int? ?? 0,
1309	      closed: json['closed'] as bool? ?? false,
1310	      archived: json['archived'] as bool? ?? false,
1311	      tags: (json['tags'] as List<dynamic>?)?.map((e) => Tag.fromJson(e)).toList(),
1312	      views: json['views'] as int? ?? 0,
1313	      likeCount: json['like_count'] as int? ?? 0,
1314	      createdAt: TimeUtils.parseUtcTime(json['created_at'] as String?),
