1317	      canVote: json['can_vote'] as bool? ?? false,
1318	      voteCount: json['vote_count'] as int? ?? 0,
1319	      userVoted: json['user_voted'] as bool? ?? false,
1320	      createdBy: (json['details'] as Map<String, dynamic>?)?['created_by'] != null
