1331	      bookmarked: topicBookmarked,
1332	      bookmarkId: topicBookmarkId,
1333	      bookmarkName: topicBookmarkName,
1334	      bookmarkReminderAt: topicBookmarkReminderAt,
1335	      hasAcceptedAnswer: hasAcceptedAnswer,
1336	      acceptedAnswerPostNumber: acceptedAnswerPostNumber,
1337	    );
1338	  }
