1441	/// 帖子列表响应
1442	class TopicListResponse {
1443	  final List<Topic> topics;
1444	  final String? moreTopicsUrl;
1445	
1446	  TopicListResponse({
1447	    required this.topics,
1448	    this.moreTopicsUrl,
1449	  });
1450	
1451	  factory TopicListResponse.fromJson(Map<String, dynamic> json) {
1452	    // Parse users map
1453	    final usersJson = json['users'] as List<dynamic>? ?? [];
1454	    final userMap = {
1455	      for (var u in usersJson)
1456	        (u['id'] as int): TopicUser.fromJson(u as Map<String, dynamic>)
1457	    };
1458	
1459	    final topicList = json['topic_list'] as Map<String, dynamic>?;
1460	    List<dynamic> topicsJson = [];
1461	    String? moreTopicsUrl;
1462	
1463	    if (topicList != null) {
1464	      topicsJson = topicList['topics'] as List<dynamic>? ?? [];
1465	      moreTopicsUrl = topicList['more_topics_url'] as String?;
1466	    } else if (json.containsKey('user_bookmark_list')) {
1467	      // 处理 /u/{username}/bookmarks.json 格式
1468	      final userBookmarkList = json['user_bookmark_list'] as Map<String, dynamic>?;
1469	      if (userBookmarkList != null) {
1470	        final bookmarks = userBookmarkList['bookmarks'] as List<dynamic>? ?? [];
1471	        moreTopicsUrl = userBookmarkList['more_bookmarks_url'] as String?;
1472	        topicsJson = bookmarks.map((b) {
1473	          final map = Map<String, dynamic>.from(b as Map);
1474	
1475	          // 提取书签元数据（必须在 id 被覆盖前取原始书签 ID）
1476	          map['_bookmark_id'] = map['id'];
1477	
1478	          // 书签对象中的 id 是书签 ID，topic_id 才是主题 ID
1479	          if (map.containsKey('topic_id')) {
1480	            map['id'] = map['topic_id'];
1481	          }
1482	          final bmName = map['name'] as String?;
1483	          if (bmName != null && bmName.isNotEmpty) {
1484	            map['_bookmark_name'] = bmName;
1485	          }
1486	          if (map['reminder_at'] != null) {
1487	            map['_bookmark_reminder_at'] = map['reminder_at'];
1488	          }
1489	          if (map['bookmarkable_type'] != null) {
1490	            map['_bookmarkable_type'] = map['bookmarkable_type'];
1491	          }
1492	
1493	          // 帖子书签：保留 linked_post_number 供跳转使用
1494	          if (map['bookmarkable_type'] == 'Post') {
1495	            final linkedPostNumber = map['linked_post_number'] as int?;
1496	            if (linkedPostNumber != null) {
1497	              map['_bookmarked_post_number'] = linkedPostNumber;
1498	            }
1499	          }
1500	
1501	          // 映射关键字段以适配 TopicCard 显示
1502	          // 1. 使用 highest_post_number 作为 posts_count
1503	          if (map.containsKey('highest_post_number')) {
1504	            map['posts_count'] = map['highest_post_number'];
1505	            map['reply_count'] = (map['highest_post_number'] as int) - 1;
1506	          }
1507	
1508	          // 2. 使用 bumped_at 作为 last_posted_at
1509	          if (map.containsKey('bumped_at') && !map.containsKey('last_posted_at')) {
1510	            map['last_posted_at'] = map['bumped_at'];
1511	          }
1512	
1513	          // 3. 将 user 转换为 posters 数组格式（用于头像叠放）
1514	          if (map.containsKey('user') && map['user'] != null) {
1515	            final user = map['user'] as Map<String, dynamic>;
1516	            final userId = user['id'] as int;
1517	
1518	            // 添加 user 到 userMap（如果不存在）
1519	            if (!userMap.containsKey(userId)) {
1520	              userMap[userId] = TopicUser.fromJson(user);
1521	            }
1522	
1523	            // 创建 posters 数组
1524	            map['posters'] = [
1525	              {
1526	                'user_id': userId,
1527	                'description': 'Original Poster',
1528	                'extras': 'latest',
1529	              }
1530	            ];
1531	
1532	            // 设置 last_poster_username
1533	            if (user.containsKey('username')) {
1534	              map['last_poster_username'] = user['username'];
1535	            }
1536	          }
1537	
1538	          // 4. 如果没有 like_count，设置为 0（书签数据中可能没有这个字段）
1539	          if (!map.containsKey('like_count')) {
1540	            map['like_count'] = 0;
1541	          }
1542	
1543	          // 5. 如果没有 views，设置为 0
1544	          if (!map.containsKey('views')) {
1545	            map['views'] = 0;
1546	          }
1547	
1548	          return map;
1549	        }).toList();
1550	      }
1551	    } else if (json.containsKey('bookmarks')) {
1552	      // 处理 /bookmarks.json 格式
1553	      final bookmarks = json['bookmarks'] as List<dynamic>? ?? [];
1554	      topicsJson = bookmarks.map((b) {
1555	        final map = Map<String, dynamic>.from(b as Map);
1556	        // 书签对象中的 id 是书签 ID，topic_id 才是主题 ID
1557	        // 为了兼容 Topic.fromJson，我们将 topic_id 赋给 id
1558	        if (map.containsKey('topic_id')) {
1559	          map['id'] = map['topic_id'];
1560	        }
1561	        return map;
1562	      }).toList();
1563	    }
1564	
1565	    return TopicListResponse(
1566	      topics: topicsJson.map((t) => Topic.fromJson(t as Map<String, dynamic>, userMap: userMap)).toList(),
1567	      moreTopicsUrl: moreTopicsUrl,
1568	    );
1569	  }
1570	}
